mapper.select:
SELECT cp.id AS id, cp.sid AS sid, cp.term AS term, sem.`name` AS termName, gra.grade_group_name AS gradeGroupName, cp.class_id AS classId, cla.class_name AS className, cp.student_id AS studentId, stu.chinese_name AS studentName, cp.date AS date, cp.type AS type, cp.frequency AS frequency, cp.remark AS remark, cp.create_id AS createId, susr.username AS createName, cp.create_time AS createTime FROM conventional_performance cp LEFT JOIN sys_semester sem ON sem.id = cp.term LEFT JOIN sys_class cla ON cla.id = cp.class_id LEFT JOIN grade_group gra ON gra.id = cla.grade_group LEFT JOIN student_info stu ON stu.id = cp.student_id LEFT JOIN sys_user_school_rel susr ON susr.school_id = cp.school_id AND susr.user_id = cp.create_id AND susr.deleted = 0 WHERE cp.deleted = 0
AND cp.school_id = #{schoolId}
AND cp.sid = #{reqModel.sid}
AND cp.term = #{reqModel.term}
AND sem.department = #{reqModel.department}
AND cp.class_id = #{reqModel.classId}
AND cp.student_id = #{reqModel.studentId}
AND cp.type = #{reqModel.type}
AND cp.date >= #{reqModel.eventStartDate}
AND cp.date <= #{reqModel.eventEndDate}
AND cp.create_time >= CONCAT(#{reqModel.createStartDate}, ' 00:00:00')
AND cp.create_time <= CONCAT(#{reqModel.createEndDate}, ' 23:59:59')
ORDER BY cp.create_time DESC
